/// <summary>
/// Extension of the <c>PurchAgreement</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(FormStr(PurchAgreement))]
final class PurchAgreement_Form_ETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>This code is used to show or hide features in Spanish companies.</remarks>
public void init()
{
    next init();

    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINPurchSalesAgreementQuotaDialog)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchPlateDaysNumber1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchHasAgreementQuotas1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchAgreementType1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINAgreementOperationId1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchCountryRegionIdOrigin1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchExecutionDueDate1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchInvoiceType1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchExecutionFromDate1)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchInvoiceType)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchExecutionFromDate1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchPlateDaysNumber)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchExecutionDueDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ALine_ETGSPAINLineCode)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINExecutionDates)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINExecutionDates_ETGSPAINPurchExecutionDueDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINExecutionDates_ETGSPAINPurchExecutionFromDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINPorts)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINPorts_ETGSPAINPurchLoadPortId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINPorts_ETGSPAINPurchUnloadPortId)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ALine_AgreementLineQuantityCommitment_ETGSPAINUnderDeliveryPct)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ALine_AgreementLineQuantityCommitment_ETGSPAINOverDeliveryPct)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINTrackingDimensions)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINTrackingDimensions_InventDimension1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINTrackingDimensions_inventBatchId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINTrackingDimensions_InventProfileId_RU)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINTrackingDimensions_InventOwnerId_RU)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINTrackingDimensions_InventGtdId_RU)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINTrackingDimensions_inventSerialId)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINAgreementQuota)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchHasAgreementQuotas)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchAgreementQuotaPeriods)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchAgreementQuotaFromDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchAgreementQuotaToDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ETGSPAINCountryRegionIdOrigin)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchCountryRegionIdOrigin)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchAgreementType)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINAgreementOperationId)).visible(currentCompanyIsSpanishCompany);        

    if (currentCompanyIsSpanishCompany == NoYes::Yes)
    {
        AgreementHeaderDefault_DS.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).mandatory(true);
        this.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchHasAgreementQuotas)).enabled(false);
    }

    this.design().controlName(formControlStr(PurchAgreement, PurchAgreementProFormaConfirm)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ETG_AgreementConfirmationProfomaRpt)).visible(!currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ButtonConfirmationETG)).visible(!currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ButtonConfirmation)).visible(currentCompanyIsSpanishCompany);
}
